@triton.jit
def _solve_multiple_lu_kernel(
    A_ptr, Bs_ptr, X_ptr,
    stride_A_batch, stride_A_n, stride_A_k,
    stride_B_batch, stride_B_n, stride_B_k,
    stride_X_batch, stride_X_n, stride_X_k,
    n, k, batch_size,
    pivot: tl.constexpr,
    BLOCK_SIZE: tl.constexpr
):
    batch_idx = tl.program_id(0)
    if batch_idx >= batch_size:
        return

    A_batch = A_ptr + batch_idx * stride_A_batch
    B_batch = Bs_ptr + batch_idx * stride_B_batch
    X_batch = X_ptr + batch_idx * stride_X_batch

    # Allocate shared memory for L and U matrices
    L = tl.shared_ptr(A_batch, (n, n), dtype=tl.float32)
    U = tl.shared_ptr(A_batch + n * stride_A_n, (n, n), dtype=tl.float32)

    # Copy A to L and U
    for i in range(n):
        for j in range(n):
            if i >= j:
                L[i, j] = A_batch[i * stride_A_n + j * stride_A_k]
            else:
                U[i, j] = A_batch[i * stride_A_n + j * stride_A_k]

    # LU decomposition with partial pivoting
    if pivot:
        for i in range(n):
            # Find pivot
            max_val = tl.abs(L[i, i])
            pivot_row = i
            for j in range(i + 1, n):
                if tl.abs(L[j, i]) > max_val:
                    max_val = tl.abs(L[j, i])
                    pivot_row = j

            # Swap rows if needed
            if pivot_row != i:
                for j in range(n):
                    temp = L[i, j]
                    L[i, j] = L[pivot_row, j]
                    L[pivot_row, j] = temp

    # Forward substitution
    for i in range(n):
        for j in range(i):
            for k_idx in range(n):
                L[i, k_idx] -= L[i, j] * L[j, k_idx]

    # Backward substitution
    for i in range(n - 1, -1, -1):
        for j in range(i + 1, n):
            for k_idx in range(n):
                U[i, k_idx] -= U[i, j] * U[j, k_idx]

    # Solve for each right-hand side
    for rhs in range(k):
        # Forward substitution
        for i in range(n):
            for j in range(i):
                B_batch[i * stride_B_n + rhs * stride_B_k] -= L[i, j] * B_batch[j * stride_B_n + rhs * stride_B_k]

        # Backward substitution
        for i in range(n - 1, -1, -1):
            for j in range(i + 1, n):
                B_batch[i * stride_B_n + rhs * stride_B_k] -= U[i, j] * B_batch[j * stride_B_n + rhs * stride_B_k]
            B_batch[i * stride_B_n + rhs * stride_B_k] /= U[i, i]

        # Copy result to output
        for i in range(n):
            X_batch[i * stride_X_n + rhs * stride_X_k] = B_batch[i * stride_B_n + rhs * stride_B_k]

