def _lu_decompose_kernel(A_ptr, L_ptr, U_ptr, P_ptr, n, stride_A, stride_L, stride_U, stride_P, BLOCK_SIZE: tl.constexpr):
    pid = tl.program_id(0)
    block_start = pid * BLOCK_SIZE
    block_end = min((pid + 1) * BLOCK_SIZE, n)

    for k in range(block_start, block_end):
        # Find pivot
        pivot_val = tl.abs(A_ptr[k * stride_A + k])
        pivot_idx = k
        for i in range(k + 1, n):
            val = tl.abs(A_ptr[i * stride_A + k])
            if val > pivot_val:
                pivot_val = val
                pivot_idx = i

        # Swap rows in A
        if pivot_idx != k:
            for j in range(n):
                temp = A_ptr[k * stride_A + j]
                A_ptr[k * stride_A + j] = A_ptr[pivot_idx * stride_A + j]
                A_ptr[pivot_idx * stride_A + j] = temp

        # Update P matrix
        if pivot_idx != k:
            temp = P_ptr[k]
            P_ptr[k] = P_ptr[pivot_idx]
            P_ptr[pivot_idx] = temp

        # Compute L and U
        for i in range(k + 1, n):
            if A_ptr[k * stride_A + k] != 0:
                L_ptr[i * stride_L + k] = A_ptr[i * stride_A + k] / A_ptr[k * stride_A + k]
                for j in range(k + 1, n):
                    A_ptr[i * stride_A + j] = A_ptr[i * stride_A + j] - L_ptr[i * stride_L + k] * A_ptr[k * stride_A + j]
            else:
                L_ptr[i * stride_L + k] = 0.0
        for j in range(k, n):
            U_ptr[k * stride_U + j] = A_ptr[k * stride_A + j]

