@triton.jit
def _qr_kernel(
    A_ptr, Q_ptr, R_ptr,
    m, n, batch_size,
    stride_am, stride_an,
    stride_qm, stride_qn,
    stride_rm, stride_rn,
    BLOCK_SIZE_M: tl.constexpr,
    BLOCK_SIZE_N: tl.constexpr,
    BLOCK_SIZE_K: tl.constexpr,
    dtype: tl.constexpr
):
    batch_idx = tl.program_id(0)
    m_idx = tl.program_id(1)
    n_idx = tl.program_id(2)

    # Load matrix A
    a_block = tl.zeros((BLOCK_SIZE_M, BLOCK_SIZE_N), dtype=dtype)
    for i in range(0, BLOCK_SIZE_M):
