                a_block[i, j] = tl.load(
                    A_ptr + batch_idx * stride_am + (m_idx * BLOCK_SIZE_M + i) * stride_an + (n_idx * BLOCK_SIZE_N + j)
                )

    # Initialize Q and R
    q_block = tl.zeros((BLOCK_SIZE_M, BLOCK_SIZE_M), dtype=dtype)
    r_block = tl.zeros((BLOCK_SIZE_M, BLOCK_SIZE_N), dtype=dtype)

    # Initialize Q as identity matrix
    for i in range(0, BLOCK_SIZE_M):
        if i < m:
            q_block[i, i] = 1.0

    # Initialize R with A values
    for i in range(0, BLOCK_SIZE_M):
        for j in range(0, BLOCK_SIZE_N):
            if i < m and j < n:
                r_block[i, j] = a_block[i, j]

    # Givens rotations for QR decomposition
    for k in range(0, min(BLOCK_SIZE_M, BLOCK_SIZE_N)):
        # Compute Givens rotation
        r_kk = r_block[k, k]
        if k + 1 < BLOCK_SIZE_M:
            r_k1k = r_block[k + 1, k]
        else:
            r_k1k = 0.0

        # Compute rotation parameters
        if abs(r_kk) < 1e-12 and abs(r_k1k) < 1e-12:
            continue

        if abs(r_kk) >= abs(r_k1k):
            c = r_kk / tl.sqrt(r_kk * r_kk + r_k1k * r_k1k)
            s = r_k1k / tl.sqrt(r_kk * r_kk + r_k1k * r_k1k)
        else:
            s = -r_k1k / tl.sqrt(r_kk * r_kk + r_k1k * r_k1k)
            c = r_kk / tl.sqrt(r_kk * r_kk + r_k1k * r_k1k)

        # Apply rotation to R
        for j in range(k, BLOCK_SIZE_N):
            temp = r_block[k, j]
            r_block[k, j] = c * temp - s * r_block[k + 1, j]
            r_block[k + 1, j] = s * temp + c * r_block[k + 1, j]

        # Apply rotation to Q
        for i in range(0, BLOCK_SIZE_M):
            temp = q_block[i, k]
            q_block[i, k] = c * temp - s * q_block[i, k + 1]
            q_block[i, k + 1] = s * temp + c * q_block[i, k + 1]

    # Store results
    for i in range(0, BLOCK_SIZE_M):
        for j in range(0, BLOCK_SIZE_N):
            if i < m and j < n:
                if j >= i:
                    tl.store(
                        R_ptr + batch_idx * stride_rm + i * stride_rn + j,
                        r_block[i, j]
                    )
                else:
                    tl.store(
                        R_ptr + batch_idx * stride_rm + i * stride_rn + j,
                        0.0
                    )

    for i in range(0, BLOCK_SIZE_M):
        for j in range(0, BLOCK_SIZE_M):
            if i < m and j < m:
                tl.store(
                    Q_ptr + batch_idx * stride_qm + i * stride_qn + j,
                    q_block[i, j]
                )

