                batch_A = A.view(-1, m, n)[batch_idx] if batch_size > 1 else A
                batch_Q, batch_R = torch.linalg.qr(batch_A, mode=mode)
                if mode == 'reduced':
                    Q[batch_idx] = batch_Q
                    R[batch_idx] = batch_R
                elif mode == 'complete':
                    Q[batch_idx] = batch_Q
                    R[batch_idx] = batch_R
                else:  # 'r'
                    R[batch_idx] = batch_R

    return (Q, R)

