import triton
import triton.language as tl

@triton.jit
def cholesky_kernel(A_ptr, L_ptr, n, BLOCK_SIZE: tl.constexpr):
    # Compute Cholesky decomposition
    for k in range(n):
        # Compute diagonal element
        if k < n:
            acc = tl.zeros((1,), dtype=tl.float32)
            for p in range(k):
                acc += L_ptr[k * n + p] * L_ptr[k * n + p]
            diag = tl.sqrt(A_ptr[k * n + k] - acc)
            L_ptr[k * n + k] = diag

        # Compute off-diagonal elements
        for i in range(k + 1, n):
            if i < n and k < n:
                acc = tl.zeros((1,), dtype=tl.float32)
                for p in range(k):
                    acc += L_ptr[i * n + p] * L_ptr[k * n + p]
                L_ptr[i * n + k] = (A_ptr[i * n + k] - acc) / L_ptr[k * n + k]

@triton.jit
def forward_substitution_kernel(L_ptr, b_ptr, x_ptr, n, k, BLOCK_SIZE: tl.constexpr):
    # Forward substitution: L * y = b
    for i in range(n):
        acc = tl.zeros((1,), dtype=tl.float32)
        for j in range(i):
            acc += L_ptr[i * n + j] * b_ptr[j * k + 0]
        b_ptr[i * k + 0] = (b_ptr[i * k + 0] - acc) / L_ptr[i * n + i]

@triton.jit
def backward_substitution_kernel(L_ptr, b_ptr, x_ptr, n, k, BLOCK_SIZE: tl.constexpr):
    # Backward substitution: L.T * x = y
    for i in range(n - 1, -1, -1):
        acc = tl.zeros((1,), dtype=tl.float32)
        for j in range(i + 1, n):
            acc += L_ptr[j * n + i] * b_ptr[j * k + 0]
        b_ptr[i * k + 0] = (b_ptr[i * k + 0] - acc) / L_ptr[i * n + i]

def fused_cholesky_solve(A: torch.Tensor, b: torch.Tensor) -> torch.Tensor:
    n, k = A.shape[0], b.shape[1]
    A = A.float()
    b = b.float()

    # Allocate output tensor
    x = torch.empty_like(b)

    # Create workspace for L
    L = torch.zeros_like(A)

    # Launch Cholesky kernel
    BLOCK_SIZE = 16
    grid = (triton.cdiv(n, BLOCK_SIZE), triton.cdiv(n, BLOCK_SIZE))
    cholesky_kernel[grid](A, L, n, BLOCK_SIZE=BLOCK_SIZE)

    # Copy b to x for in-place operations
    x.copy_(b)

    # Forward substitution
    for i in range(k):
        forward_substitution_kernel[grid](L, x, x, n, 1, BLOCK_SIZE=BLOCK_SIZE)

    # Backward substitution
    for i in range(k):
        backward_substitution_kernel[grid](L, x, x, n, 1, BLOCK_SIZE=BLOCK_SIZE)

    return x

import torch
import triton
import triton.language as tl

@triton.jit
def matmul_kernel(
    A, B, C,
    M, N, K,
    stride_am, stride_ak,
    stride_bk, stride_bn,
    stride_cm, stride_cn,
    BLOCK_SIZE_M: tl.constexpr,
    BLOCK_SIZE_N: tl.constexpr,
    BLOCK_SIZE_K: tl.constexpr,
    GROUP_SIZE_M: tl.constexpr,
    ACTIVATION: tl.constexpr
):
    pid = tl.program_id(axis=0)
    num_pid_m = tl.cdiv(M, BLOCK_SIZE_M)
    num_pid_n = tl.cdiv(N, BLOCK_SIZE_N)
    num_pid_in_group = GROUP_SIZE_M * num_pid_n
    group_id = pid // num_pid_in_group
    first_pid_m = group_id * GROUP_SIZE_M
    group_size_m = min(num_pid_m - first_pid_m, GROUP_SIZE_M)
    pid_m = first_pid_m + (pid % group_size_m)
    pid_n = (pid % num_pid_in_group) // group_size_m

    offs_am = (pid_m * BLOCK_SIZE_M + tl.arange(0, BLOCK_SIZE_M)) % M
    offs_bn = (pid_n * BLOCK_SIZE_N + tl.arange(0, BLOCK_SIZE_N)) % N
    offs_k = tl.arange(0, BLOCK_SIZE_K)
    a_ptrs = A + (offs_am[:, None] * stride_am + offs_k[None, :] * stride_ak)
    b_ptrs = B + (offs_k[:, None] * stride_bk + offs_bn[None, :] * stride_bn)

    accumulator = tl.zeros((BLOCK_SIZE_M, BLOCK_SIZE_N), dtype=tl.float32)
    for k in range(0, tl.cdiv(K, BLOCK_SIZE_K)):
        a = tl.load(a_ptrs, mask=offs_k[None, :] < K - k * BLOCK_SIZE_K, other=0.0)
        b = tl.load(b_ptrs, mask=offs_k[:, None] < K - k * BLOCK_SIZE_K, other=0.0)
        accumulator += tl.dot(a, b)
        a_ptrs += BLOCK_SIZE_K * stride_ak
        b_ptrs += BLOCK_SIZE_K * stride_bk

    if ACTIVATION == "leaky_relu":
        accumulator = leaky_relu(accumulator)
    c = accumulator.to(tl.float16)

    offs_cm = pid_m * BLOCK_SIZE_M + tl.arange(0, BLOCK_SIZE_M)
    offs_cn = pid_n * BLOCK_SIZE_N + tl.arange(0, BLOCK_SIZE_N)
    c_ptrs = C + (offs_cm[:, None] * stride_cm + offs_cn[None, :] * stride_cn)
    c_mask = (offs_cm[:, None] < M) & (offs_cn[None, :] < N)
    tl.store(c_ptrs, c, mask=c_mask)

@triton.jit
def leaky_relu(x):
    return tl.where(x >= 0, x, 0.01 * x)

def matmul(input, other, *, out=None):
    if input.dim() == 1 and other.dim() == 1:
        # Dot product
        if out is not None:
            raise ValueError("out parameter not supported for 1D dot product")
        return torch.dot(input, other)
    elif input.dim() == 1 and other.dim() == 2:
        # Matrix-vector product
        if out is not None:
            torch.mm(input.unsqueeze(0), other, out=out)
            return out
        return torch.mv(other, input)
    elif input.dim() == 2 and other.dim() == 1:
        # Matrix-vector product
        if out is not None:
            torch.mm(input, other.unsqueeze(1), out=out)
            return out
        return torch.mv(input, other)
    elif input.dim() == 2 and other.dim() == 2:
        # Matrix-matrix product
        if out is not None:
            torch.mm(input, other, out=out)
            return out
        return torch.mm(input, other)
    else:
        # Batched matrix multiply
        if out is not None:
            torch.bmm(input, other, out=out)
            return out
        return torch.bmm(input, other)

