@triton.jit
def lu_kernel(
    A_ptr, P_ptr, L_ptr, U_ptr,
    m, n, batch_size,
    stride_am, stride_an,
    stride_pm, stride_pn,
    stride_lm, stride_ln,
    stride_um, stride_un,
    BLOCK_SIZE: tl.constexpr
):
    batch_idx = tl.program_id(0)
    if batch_idx >= batch_size:
        return

    A_batch = A_ptr + batch_idx * stride_am
    P_batch = P_ptr + batch_idx * stride_pm
    L_batch = L_ptr + batch_idx * stride_lm
    U_batch = U_ptr + batch_idx * stride_um

    # Initialize L and U matrices
    for i in range(m):
        for j in range(n):
            if i == j:
                tl.store(U_batch + i * stride_um + j * stride_un, tl.load(A_batch + i * stride_am + j * stride_an))
            elif i > j:
                tl.store(L_batch + i * stride_lm + j * stride_ln, tl.load(A_batch + i * stride_am + j * stride_an))
            else:
                tl.store(U_batch + i * stride_um + j * stride_un, tl.load(A_batch + i * stride_am + j * stride_an))

    # LU decomposition with partial pivoting
    for k in range(min(m, n)):
        # Find pivot
        pivot_val = tl.load(U_batch + k * stride_um + k * stride_un)
        pivot_idx = k

        for i in range(k + 1, m):
            val = tl.load(U_batch + i * stride_um + k * stride_un)
            if tl.abs(val) > tl.abs(pivot_val):
                pivot_val = val
                pivot_idx = i

        # Swap rows in A
        if pivot_idx != k:
            for j in range(n):
                temp = tl.load(A_batch + k * stride_am + j * stride_an)
                tl.store(A_batch + k * stride_am + j * stride_an, tl.load(A_batch + pivot_idx * stride_am + j * stride_an))
                tl.store(A_batch + pivot_idx * stride_am + j * stride_an, temp)

        # Update P matrix
        if pivot_idx != k:
            for j in range(n):
                temp = tl.load(P_batch + k * stride_pm + j * stride_pn)
                tl.store(P_batch + k * stride_pm + j * stride_pn, tl.load(P_batch + pivot_idx * stride_pm + j * stride_pn))
                tl.store(P_batch + pivot_idx * stride_pm + j * stride_pn, temp)

        # Compute multipliers
        for i in range(k + 1, m):
            if tl.abs(pivot_val) > 1e-12:
                multiplier = tl.load(A_batch + i * stride_am + k * stride_an) / pivot_val
                tl.store(L_batch + i * stride_lm + k * stride_ln, multiplier)

                # Update remaining elements
                for j in range(k + 1, n):
                    val = tl.load(A_batch + i * stride_am + j * stride_an)
                    update = val - multiplier * tl.load(A_batch + k * stride_am + j * stride_an)
                    tl.store(A_batch + i * stride_am + j * stride_an, update)
            else:
                tl.store(L_batch + i * stride_lm + k * stride_ln, 0.0)

def lu(A, *, pivot=True, out=None):
    if not pivot:
        # For no pivoting, we just return empty permutation matrix
        batch_dims = A.shape[:-2]
        m, n = A.shape[-2], A.shape[-1]

        if out is not None:
            P, L, U = out
        else:
            P = torch.empty((*batch_dims, m, n), dtype=torch.int64, device=A.device)
            L = torch.empty((*batch_dims, m, n), dtype=A.dtype, device=A.device)
            U = torch.empty((*batch_dims, m, n), dtype=A.dtype, device=A.device)

        # Initialize L and U
        for i in range(m):
            for j in range(n):
                if i == j:
                    U[..., i, j] = A[..., i, j]
                elif i > j:
                    L[..., i, j] = A[..., i, j]
                else:
                    U[..., i, j] = A[..., i, j]

        # No pivoting LU decomposition
        for k in range(min(m, n)):
            for i in range(k + 1, m):
                if abs(U[..., k, k]) > 1e-12:
                    multiplier = L[..., i, k] / U[..., k, k]
                    L[..., i, k] = multiplier
                    for j in range(k + 1, n):
                        U[..., i, j] = U[..., i, j] - multiplier * U[..., k, j]
                else:
                    L[..., i, k] = 0.0

        return (P, L, U)

    # With pivoting
    batch_dims = A.shape[:-2]
    m, n = A.shape[-2], A.shape[-1]

    if out is not None:
        P, L, U = out
    else:
        P = torch.empty((*batch_dims, m, n), dtype=torch.int64, device=A.device)
        L = torch.empty((*batch_dims, m, n), dtype=A.dtype, device=A.device)
        U = torch.empty((*batch_dims, m, n), dtype=A.dtype, device=A.device)

    # Initialize permutation matrix
    for i in range(m):
        for j in range(n):
            if i == j:
                P[..., i, j] = 1
            else:
                P[..., i, j] = 0

    # Initialize L and U
    for i in range(m):
        for j in range(n):
            if i == j:
                U[..., i, j] = A[..., i, j]
            elif i > j:
                L[..., i, j] = A[..., i, j]
            else:
                U[..., i, j] = A[..., i, j]

    # LU decomposition with partial pivoting
    for k in range(min(m, n)):
        # Find pivot
        pivot_val = U[..., k, k]
        pivot_idx = k

        for i in range(k + 1, m):
            val = U[..., i, k]
            if abs(val) > abs(pivot_val):
                pivot_val = val
                pivot_idx = i

        # Swap rows in A and P
        if pivot_idx != k:
            # Swap rows in U
            temp = U[..., k, :].clone()
            U[..., k, :] = U[..., pivot_idx, :]
            U[..., pivot_idx, :] = temp

            # Swap rows in L
            temp = L[..., k, :].clone()
            L[..., k, :] = L[..., pivot_idx, :]
            L[..., pivot_idx, :] = temp

            # Swap rows in P
            temp = P[..., k, :].clone()
            P[..., k, :] = P[..., pivot_idx, :]
            P[..., pivot_idx, :] = temp

        # Compute multipliers and update remaining elements
        for i in range(k + 1, m):
            if abs(pivot_val) > 1e-12:
                multiplier = L[..., i, k] / pivot_val
                L[..., i, k] = multiplier

                for j in range(k + 1, n):
                    U[..., i, j] = U[..., i, j] - multiplier * U[..., k, j]
            else:
                L[..., i, k] = 0.0

    return (P, L, U)

