@triton.jit
def _determinant_lu_kernel(
    A_ptr, 
    out_ptr, 
    n, 
    batch_size,
    pivot: tl.constexpr,
    BLOCK_SIZE: tl.constexpr
):
    batch_idx = tl.program_id(0)
    if batch_idx >= batch_size:
        return

    A_base = A_ptr + batch_idx * n * n
    out_base = out_ptr + batch_idx

    # Initialize determinant
    det = tl.full([1], 1.0, dtype=tl.float64)
    sign = tl.full([1], 1.0, dtype=tl.float64)

    # Copy matrix for LU decomposition
    A = tl.load(A_base + tl.arange(0, n)[:, None] * n + tl.arange(0, n)[None, :])

    # LU decomposition with partial pivoting
    for k in range(n):
        if pivot:
            # Find pivot
            max_val = tl.abs(A[k, k])
            pivot_row = k
            for i in range(k + 1, n):
                if tl.abs(A[i, k]) > max_val:
                    max_val = tl.abs(A[i, k])
                    pivot_row = i

            # Swap rows if needed
            if pivot_row != k:
                for j in range(n):
                    temp = A[k, j]
                    A[k, j] = A[pivot_row, j]
                    A[pivot_row, j] = temp
                sign = -sign

        # Check for zero pivot
        if tl.abs(A[k, k]) < 1e-12:
            det = tl.full([1], 0.0, dtype=tl.float64)
            break

        # Update determinant
        det = det * A[k, k]

        # Eliminate column
        for i in range(k + 1, n):
            if tl.abs(A[k, k]) > 1e-12:
                factor = A[i, k] / A[k, k]
                for j in range(k + 1, n):
                    A[i, j] = A[i, j] - factor * A[k, j]
                A[i, k] = factor

    # Store result
    tl.store(out_base, det)

def determinant_lu(A, *, pivot=True, out=None):
    if A.dim() < 2:
        raise ValueError("Input tensor must have at least 2 dimensions")

    batch_dims = A.shape[:-2]
    n = A.shape[-1]
    if A.shape[-2] != n:
        raise ValueError("Input tensor must represent square matrices")

    batch_size = 1
    for dim in batch_dims:
        batch_size *= dim

    if out is None:
        out = torch.empty(batch_size, dtype=torch.float64, device=A.device)
    else:
        if out.shape != (batch_size,):
            raise ValueError("Output tensor must have shape (*,)")

    if batch_size > 0:
        grid = (batch_size, 1, 1)
        _determinant_lu_kernel[grid](
            A.data_ptr(),
            out.data_ptr(),
            n,
            batch_size,
            pivot,
            BLOCK_SIZE=32
        )

    if len(batch_dims) == 0:
        return out[0]
    else:
        return out.view(batch_dims)

