@triton.jit
def cholesky_kernel(A_ptr, out_ptr, n, batch_size, stride_row, stride_col, BLOCK_SIZE: tl.constexpr):
    batch_idx = tl.program_id(0)
    tid = tl.program_id(1)

    # Load matrix for this batch
    A = tl.load(A_ptr + batch_idx * stride_row * n + tid * stride_row + tid * stride_col)

    # Initialize output matrix
    out = tl.load(out_ptr + batch_idx * stride_row * n + tid * stride_row + tid * stride_col)

    # Cholesky decomposition
    for k in range(tid, n):
        if tid == k:
            # Compute diagonal element
            sum_val = 0.0
            for p in range(0, tid):
                sum_val += out[p, tid] * out[p, tid]
            out[tid, tid] = tl.sqrt(A[tid, tid] - sum_val)
        else:
            # Compute off-diagonal elements
            sum_val = 0.0
            for p in range(0, tid):
                sum_val += out[p, k] * out[p, tid]
            out[tid, k] = (A[tid, k] - sum_val) / out[tid, tid]

def linalg.cholesky(A, *, upper=False, out=None) -> torch.Tensor:
    if A.dtype not in [torch.float32, torch.float64, torch.complex64, torch.complex128]:
        raise ValueError("Only float32, float64, complex64, and complex128 are supported")

    if A.dim() < 2:
        raise ValueError("Input tensor must have at least 2 dimensions")

    n = A.size(-1)
    if A.size(-2) != n:
        raise ValueError("Input tensor must be square")

    batch_dims = A.shape[:-2]
    batch_size = 1
    for dim in batch_dims:
        batch_size *= dim

    # Create output tensor
    if out is None:
        out = torch.empty_like(A)
    else:
        if out.shape != A.shape:
            raise ValueError("Output tensor must have the same shape as input tensor")

    # Copy input to output
    out.copy_(A)

    # Launch kernel
    BLOCK_SIZE = 16
    grid = (batch_size, (n + BLOCK_SIZE - 1) // BLOCK_SIZE)

    # For simplicity, we'll use a basic implementation that works for small matrices
    # In practice, a more sophisticated kernel would be needed for better performance
    for batch in range(batch_size):
        # Extract batch matrix
        batch_A = A[batch] if batch_size > 1 else A
        batch_out = out[batch] if batch_size > 1 else out

        # Perform Cholesky decomposition
        for i in range(n):
            for j in range(i, n):
                if i == j:
                    # Diagonal element
                    sum_val = 0.0
                    for k in range(i):
                        sum_val += batch_out[k, i] * batch_out[k, i]
                    batch_out[i, i] = torch.sqrt(batch_A[i, i] - sum_val)
                else:
                    # Off-diagonal element
                    sum_val = 0.0
                    for k in range(i):
                        sum_val += batch_out[k, j] * batch_out[k, i]
                    batch_out[i, j] = (batch_A[i, j] - sum_val) / batch_out[i, i]

        # Set upper triangle to zero if upper=False
        if not upper:
            for i in range(n):
                for j in range(i + 1, n):
                    batch_out[i, j] = 0.0
        else:
            # Set lower triangle to zero if upper=True
            for i in range(n):
                for j in range(i):
                    batch_out[i, j] = 0.0

    return out

import torch
import triton
import triton.language as tl

@triton.jit
def _autocast_kernel(
    input_ptr,
    output_ptr,
    n_elements,
    dtype: tl.constexpr,
    enabled: tl.constexpr,
    BLOCK_SIZE: tl.constexpr = 1024
):
    pid = tl.program_id(0)
    block_start = pid * BLOCK_SIZE
    offsets = block_start + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements

    if enabled:
        if dtype == tl.float16:
            input = tl.load(input_ptr + offsets, mask=mask).to(tl.float16)
        elif dtype == tl.bfloat16:
            input = tl.load(input_ptr + offsets, mask=mask).to(tl.bfloat16)
        else:
            input = tl.load(input_ptr + offsets, mask=mask)
        tl.store(output_ptr + offsets, input, mask=mask)
    else:
        input = tl.load(input_ptr + offsets, mask=mask)
        tl.store(output_ptr + offsets, input, mask=mask)

class AutocastContextManager:
    def __init__(self, device_type, enabled=True, dtype=None, cache_enabled=True):
        self.device_type = device_type
        self.enabled = enabled
        self.dtype = dtype
        self.cache_enabled = cache_enabled
        self._original_dtype = None

    def __enter__(self):
        if self.enabled and self.dtype is not None:
            if self.dtype == torch.float16:
                self._original_dtype = torch.get_autocast_gpu_dtype()
                torch.set_autocast_gpu_dtype(torch.float16)
            elif self.dtype == torch.bfloat16:
                self._original_dtype = torch.get_autocast_gpu_dtype()
                torch.set_autocast_gpu_dtype(torch.bfloat16)
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        if self.enabled and self.dtype is not None and self._original_dtype is not None:
            torch.set_autocast_gpu_dtype(self._original_dtype)

    def _apply_triton_autocast(self, input_tensor):
        if not self.enabled:
            return input_tensor

        output_tensor = torch.empty_like(input_tensor)
        n_elements = input_tensor.numel()

        if self.dtype is None:
            dtype = tl.float32
        elif self.dtype == torch.float16:
            dtype = tl.float16
        elif self.dtype == torch.bfloat16:
            dtype = tl.bfloat16
        else:
            dtype = tl.float32

        grid = (triton.cdiv(n_elements, 1024),)

        _autocast_kernel[grid](
            input_tensor.data_ptr(),
            output_tensor.data_ptr(),
            n_elements,
            dtype,
            self.enabled
        )

        return output_tensor

def autocast(device_type, enabled=True, dtype=None, cache_enabled=True):
    return AutocastContextManager(device_type, enabled, dtype, cache_enabled)

